var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"잡았나...?","JPN":"やった……？","ENG":"Did we get her...?","TWN":"抓住了嗎……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아직... 안 돼...","JPN":"まだ……ダメ……","ENG":"Not... yet...","TWN":"還……沒有……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"갈 거야. 나도... 갈 거야.","JPN":"行くんだ。私も……行くんだ。","ENG":"I'm going. I'm... going too.","TWN":"我要去，我也……要去。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히익! 또 일어났어!","JPN":"ひいっ！　また立ち上がった！","ENG":"Eek! She got back up again!","TWN":"咿！她又站起來了！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"흡혈귀라는 건 피만 있으면 얼마든지 되살아나는 거군요.","JPN":"吸血鬼って、血があればいくらでも蘇るものなんですね。","ENG":"So vampires can revive as long as they have blood.","TWN":"吸血鬼好像只要有血，就能一直復活呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"흥미로운데요?","JPN":"これは興味深い。","ENG":"Interesting.","TWN":"挺有意思的呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"재미 하나도 없거든?","JPN":"全然面白くないし。","ENG":"There's nothing interesting about it.","TWN":"一點也不好笑好嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"피를 흡수하면 체력도 다시 돌아오는 것 같아. 지치도록 유도해선 끝이 안 나겠어.","JPN":"血を飲むと体力も復活するみたい。疲れさせるだけじゃ切りがないよ。","ENG":"Looks like she gets her strength back when she absorbs blood too. If we just try to wear her out, this will never end.","TWN":"吸了血之後體力也會恢復。要是只想把她耗到精疲力盡，恐怕沒完沒了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"...만나야 해...","JPN":"……会わなきゃ……","ENG":"...I have to go...","TWN":"……我要見到他們……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어떻게 해서든... 다시... 그곳으로...","JPN":"どうやってでも……また……あそこに……","ENG":"No matter what... I have to go back... there and...","TWN":"無論如何……我都要再回到那個地方……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어라? 저건...","JPN":"あれ？　あれは……","ENG":"Huh? That's...","TWN":"咦？那是……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"분노나 적의가 아니야...","JPN":"怒りや敵意じゃない……","ENG":"It's not anger or hostility...","TWN":"不是憤怒，也不是敵意……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"...이 감정은...","JPN":"……この感情は……","ENG":"...This feeling is...","TWN":"……這種情感是……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SCIENTIST_VOICE_NULL_NULL","text":{"KOREA":"B1-15는 최종 적응 시험에서 낙오.","JPN":"B1-15は最終適応試験で脱落。","ENG":"B1-15 has been eliminated in the final adaptation test.","TWN":"B1-15在最終適應測試中淘汰。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SCIENTIST_VOICE_NULL_NULL","text":{"KOREA":"실험체 중 B2-1만이 유일하게 생존했습니다.","JPN":"実験体のうち、B2-1だけが唯一生存しました。","ENG":"Among the test subjects, only B2-1 survived.","TWN":"實驗體中，只有B2-1倖存。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"수고했어.","JPN":"ご苦労だった。","ENG":"Good work.","TWN":"辛苦了。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"이걸로 창백한 달의 인자를 받아들이는 조건은 이성을 넘어선 생존본능이란 게 입증 됐네.","JPN":"これで青白い月の因子を受け止める条件は、理性を超えた生存本能だということが立証された。","ENG":"This proves that the condition for accepting the Pale Moon Factor is a survival instinct that transcends reason.","TWN":"這樣一來就證明能接受蒼月因子的條件，是超越理性的生存本能。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"제대로 된 성과를 하나라도 건져서 다행이야.","JPN":"一個体だけでもまともな成果があったのは幸いだ。","ENG":"Good thing we managed to get at least one proper result out of this.","TWN":"幸好還取得了一點像樣的成果，還算不錯。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SCIENTIST_VOICE_NULL_NULL","text":{"KOREA":"앞으로가 걱정이군요. B2-1은 지금까지 실험에 적극적으로 참여하던 몇 안되던 개체였습니다.","JPN":"これからが心配ですね。B2-1は今まで実験に積極的に参加していた数少ない個体の1つでした。","ENG":"The future concerns me. B2-1 was one of the few subjects who had actively participated in the experiments until now.","TWN":"接下來真讓人擔心啊。B2-1是至今為止少數積極參與實驗的個體。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SCIENTIST_VOICE_NULL_NULL","text":{"KOREA":"그리고 그런 동기를 제공해왔던 건 B1-15의 생존이었죠.","JPN":"そしてその動機を提供してきたのが、B1-15の生存でした。","ENG":"And what had motivated that was B1-15's survival.","TWN":"而促使她這麼做的動機，一直都是B1-15的存在。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SCIENTIST_VOICE_NULL_NULL","text":{"KOREA":"아시다시피 B1-15는 B2-1의...","JPN":"ご存じのとおり、B1-15はB2-1の……","ENG":"As you know, B1-15 is B2-1's...","TWN":"如你所知，B1-15是B2-1的……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"걱정할 필요 없어. B2-1은 B1-15가 없어도 이제 우릴 거스르지 못할 거야.","JPN":"心配する必要はない。B2-1はB1-15がいなくても、もう私たちに逆らうことはできないはずだ。","ENG":"There's no need to worry. B2-1 won't be able to defy us anymore, even without B1-15.","TWN":"不用擔心。就算沒有B1-15，B2-1也不會再違抗我們了。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"왜냐하면 그 아이 몸속엔, 자신이 살아남기 위해 마신 B1-15의 피가 흐르고 있으니까.","JPN":"あの子の体には、自分が生き残るために飲んだB1-15の血が流れているからな。","ENG":"Because B1-15's blood, the blood she drank to survive, is now flowing inside her.","TWN":"因為那孩子體內流淌著自己為了生存，而喝下的B1-15的血。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그렇지?","JPN":"そうだろう？","ENG":"Isn't that right?","TWN":"對吧？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"B2-1.","JPN":"B2-1。","ENG":"B2-1.","TWN":"B2-1。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 감정은... 닿지 못하는 것에 대한 슬픔...","JPN":"この感情は……届かないことへの悲しみ……","ENG":"This feeling is... sorrow over something she can never reach...","TWN":"這份情感是……對無法觸及之物的悲傷……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"후회.","JPN":"後悔。","ENG":"Regret.","TWN":"還有後悔。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"톱으로 다 쓸어버리고 다니는 저 싸움광이... 슬픔 같은 걸 느낀다고?","JPN":"ノコギリで何もかもなぎ倒し回ってるあの戦闘狂が……悲しみなんてものを感じてるだって？","ENG":"That chainsaw-swinging battle maniac... feels something like sorrow?","TWN":"那個拿著電鋸到處砍人的戰鬥狂……居然會有悲傷這種情緒？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"기밀작전이라고 했죠?","JPN":"機密作戦だって言ってましたよね？","ENG":"This is a classified operation, right?","TWN":"你們說是機密作戰對吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"당신들을 죽이고 싶진 않아요. 한 명만 쓸모없어지면, 내가 대신 가줄 테니까.","JPN":"あなたたちを殺したくはないんです。1人だけ使い物にならなくすれば、私が代わりに行ける。","ENG":"I don't want to kill you. If even one of you becomes unusable, I'll go in your place.","TWN":"我不想殺你們。只要有一個人不能去，我就可以替補他。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};